    return len(_messages)


def deduplicate():
    """Remove duplicate messages. Useful for batch cleanup."""
    global _messages
    seen = set()
    unique = []
    for m in _messages:
        key = m if isinstance(m, str) else str(m)
        if key not in seen:
            seen.add(key)
            unique.append(m)
    _messages = unique
