        return "locked_B"

    def step_lock_a_and_transfer():
        acquire("A")  # DEADLOCK: A is held by the other transfer
        _state["B"] -= amount
        _state["A"] += amount
        release("A")
        release("B")
        return "transferred_b_to_a"

    return step_lock_b, step_lock_a_and_transfer


