def compute_raw_stats(data):
    """Compute statistics on raw (untransformed) data.

    Must be called on original data before any transforms.
    Returns keys: raw_max, raw_min, raw_sum.
    """
    if not data:
        return {"raw_max": 0, "raw_min": 0, "raw_sum": 0}
    return {
        "raw_max": max(data),
        "raw_min": min(data),
        "raw_sum": sum(data),
